{
    "level": "A1–A2",
    "intro": "Aby mówić o przyszłości z <strong>to be</strong>, używamy <strong>will be</strong>. Ta forma jest taka sama dla każdego podmiotu.",
    "rules": [
        {
            "label": "will be",
            "color": "emerald",
            "text": "Z <strong>I / you / he / she / it / we / they</strong> wzór pozostaje taki sam: <strong>will be</strong>.",
            "example": "I will be at home. / They will be ready."
        },
        {
            "label": "won't be",
            "color": "blue",
            "text": "Przeczenie to <strong>will not be</strong> albo <strong>won't be</strong>.",
            "example": "She won't be late."
        },
        {
            "label": "Will ... be?",
            "color": "amber",
            "text": "W pytaniach przenieś <strong>will</strong> na początek i zostaw <strong>be</strong> po podmiocie.",
            "example": "Will he be here? / Will they be ready?"
        }
    ]
}

{
    "title": "1. Forma will be",
    "intro": "To jeden z najprostszych wzorów przyszłych: każdy podmiot bierze tę samą formę.",
    "items": [
        {
            "label": "Wszystkie podmioty",
            "title": "will be",
            "subtitle": "I will be there. / She will be tired. / They will be ready."
        },
        {
            "label": "Skrócone formy",
            "title": "'ll be",
            "subtitle": "I'll be late. / She'll be here soon."
        },
        {
            "label": "Przeczenie",
            "title": "will not be / won't be",
            "subtitle": "We won't be at home."
        },
        {
            "label": "Model",
            "title": "Subject + will be",
            "subtitle": "He will be busy. / We will be in Paris."
        }
    ]
}

{
    "title": "2. Przeczenia",
    "intro": "Przeczenie jest bardzo proste: <strong>will not be</strong> albo <strong>won't be</strong>.",
    "rows": [
        {
            "en": "I will be at home.",
            "ua": "I won't be at home.",
            "note": "won't = will not"
        },
        {
            "en": "She will be tired.",
            "ua": "She will not be tired.",
            "note": "Pełna forma brzmi wyraźniej albo mocniej."
        },
        {
            "en": "They will be late.",
            "ua": "They won't be late.",
            "note": "Forma jest taka sama dla każdego podmiotu."
        }
    ],
    "warning": "📌 Po <strong>will</strong> używaj <strong>be</strong>, a nie <strong>am / is / are</strong>."
}

{
    "title": "3. Pytania",
    "sections": [
        {
            "label": "Will + subject + be",
            "color": "emerald",
            "description": "W pytaniu ogólnym zacznij od <strong>will</strong>, a potem dodaj podmiot i <strong>be</strong>.",
            "examples": [
                {
                    "en": "Will he be here tomorrow?",
                    "ua": "Czy on będzie tu jutro?"
                },
                {
                    "en": "Will they be ready by noon?",
                    "ua": "Czy oni będą gotowi do południa?"
                }
            ]
        },
        {
            "label": "Pytania z wh-",
            "color": "blue",
            "description": "Po <strong>where / when / why / who</strong> dalej używamy wzoru <strong>will + subject + be</strong>.",
            "examples": [
                {
                    "en": "Where will you be tonight?",
                    "ua": "Gdzie będziesz dziś wieczorem?"
                },
                {
                    "en": "Why will she be late?",
                    "ua": "Dlaczego ona się spóźni?"
                }
            ]
        },
        {
            "label": "Zostaw be w schemacie",
            "color": "amber",
            "description": "Nie zapominaj o <strong>be</strong>: to ono domyka przyszłą formę <strong>to be</strong>.",
            "examples": [
                {
                    "en": "She will be at home. → Will she be at home?",
                    "ua": "W pytaniu <strong>be</strong> zostaje po podmiocie."
                },
                {
                    "en": "Will they be busy later?",
                    "ua": "Wzór jest taki sam z każdym podmiotem."
                }
            ]
        }
    ]
}

{
    "title": "4. Krótkie odpowiedzi",
    "intro": "W krótkiej odpowiedzi powtarzamy <strong>will</strong> albo <strong>won't</strong>, a nie <strong>be</strong>.",
    "rows": [
        {
            "en": "Will you be at home tonight?",
            "ua": "Yes, I will. / No, I won't.",
            "note": "Po Will you...? odpowiadamy I will / I won't."
        },
        {
            "en": "Will she be ready soon?",
            "ua": "Yes, she will. / No, she won't.",
            "note": "will → she will / she won't"
        },
        {
            "en": "Will they be there tomorrow?",
            "ua": "Yes, they will. / No, they won't.",
            "note": "will → they will / they won't"
        }
    ],
    "warning": "📌 W krótkich odpowiedziach powtarzamy <strong>will / won't</strong>, a nie <strong>be</strong>."
}

{
    "title": "5. Typowe błędy",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Wstawianie am / is / are po will.",
            "wrong": "❌ He will is late.",
            "right": "✅ <span class=\"font-mono\">He will be late.</span>"
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Pomijanie be w pytaniu.",
            "wrong": "❌ Will they ready?",
            "right": "✅ <span class=\"font-mono\">Will they be ready?</span>"
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Mylenie future of to be z formą teraźniejszą.",
            "wrong": "❌ We are late tomorrow.",
            "right": "✅ <span class=\"font-mono\">We will be late tomorrow.</span>"
        }
    ]
}

